from collections import Counter
import statistics

def tokeniser_byte_stats(tokenizer, texts: list[str]) -> dict:
    """Compute bytes-per-token statistics for a tokeniser on a corpus."""
    byte_lengths = []
    for text in texts:
        ids = tokenizer.encode(text)
        tokens = tokenizer.convert_ids_to_tokens(ids)
        for tok in tokens:
            if isinstance(tok, str):
                # Tiktoken-style tokens may start with 'Ġ' (GPT-2 space marker)
                clean = tok.replace('Ġ', ' ').replace('Ċ', '\n')
                byte_lengths.append(len(clean.encode('utf-8')))
            else:
                byte_lengths.append(1)  # raw byte fallback
    counts = Counter(byte_lengths)
    return {
        'mean_bytes_per_token': statistics.mean(byte_lengths),
        'median': statistics.median(byte_lengths),
        'distribution': {k: v / len(byte_lengths)
                         for k, v in sorted(counts.items())},
    }

# Typical values (English prose):
# GPT-2 BPE:           mean ≈ 3.8 bytes/token
# LLaMA SentencePiece: mean ≈ 3.4 bytes/token
# GPT-4o tiktoken:     mean ≈ 4.2 bytes/token (larger vocab → longer tokens)

import unicodedata

SCRIPT_RANGES = {
    'latin':   [(0x0000, 0x024F)],
    'arabic':  [(0x0600, 0x06FF), (0x0750, 0x077F)],
    'cjk':     [(0x4E00, 0x9FFF), (0x3040, 0x30FF), (0xAC00, 0xD7AF)],
    'emoji':   [(0x1F300, 0x1FAFF)],
}

def classify_script(char: str) -> str:
    cp = ord(char)
    for script, ranges in SCRIPT_RANGES.items():
        if any(lo <= cp <= hi for lo, hi in ranges):
            return script
    return 'other'

def bpb_by_script(text: str, total_bits: float) -> dict[str, float]:
    """Partition BPB contribution by Unicode script block.

    Assumes bits are uniformly distributed over bytes for illustration.
    In practice, compute this from per-token log-probs aligned to script.
    """
    byte_counts: dict[str, int] = {}
    for char in text:
        script = classify_script(char)
        byte_counts[script] = byte_counts.get(script, 0) + len(char.encode('utf-8'))
    total_bytes = sum(byte_counts.values())
    bits_per_byte_overall = total_bits / total_bytes
    # Fraction of bytes per script → approximate per-script BPB
    return {
        script: round(bits_per_byte_overall, 3)  # replace with per-script loss
        for script, count in byte_counts.items()
    }

def classify_document_quality(
    model_bpb: float,
    low_threshold: float = 0.5,
    high_threshold: float = 1.2,
) -> str:
    """Rough quality classification based on BPB relative to a reference model."""
    if model_bpb < low_threshold:
        return 'near-duplicate or memorised'
    elif model_bpb > high_threshold:
        return 'out-of-distribution or low quality'
    else:
        return 'normal'

